+/// Standard OpenAI chat completion success response.
+fn openai_success_response(
+    resp_id: &str,
+    text: &str,
+    prompt_tokens: u32,
+    completion_tokens: u32,
+) -> serde_json::Value {
+    json!({
+        "id": resp_id,
+        "object": "chat.completion",
+        "created": 1700000000,
+        "model": "gpt-4o",
+        "choices": [{
+            "index": 0,
+            "message": {
+                "role": "assistant",
+                "content": text
+            },
+            "finish_reason": "stop"
+        }],
+        "usage": {
+            "prompt_tokens": prompt_tokens,
+            "completion_tokens": completion_tokens,
+            "total_tokens": prompt_tokens + completion_tokens
+        }
+    })
+}
+
+/// OpenAI tool_calls response.
+fn openai_tool_use_response(
+    resp_id: &str,
+    call_id: &str,
+    fn_name: &str,
+    fn_args: &str,
+    prompt_tokens: u32,
+    completion_tokens: u32,
+) -> serde_json::Value {
+    json!({
+        "id": resp_id,
+        "object": "chat.completion",
+        "created": 1700000000,
+        "model": "gpt-4o",
+        "choices": [{
+            "index": 0,
+            "message": {
+                "role": "assistant",
+                "content": null,
+                "tool_calls": [{
+                    "id": call_id,
+                    "type": "function",
+                    "function": {
+                        "name": fn_name,
+                        "arguments": fn_args
+                    }
+                }]
+            },
+            "finish_reason": "tool_calls"
+        }],
+        "usage": {
+            "prompt_tokens": prompt_tokens,
+            "completion_tokens": completion_tokens,
+            "total_tokens": prompt_tokens + completion_tokens
+        }
+    })
+}
+
+/// OpenAI API error envelope.
+fn openai_error(error_type: &str, message: &str, code: Option<&str>) -> serde_json::Value {
+    json!({
+        "error": {
+            "message": message,
+            "type": error_type,
+            "param": null,
+            "code": code
+        }
+    })
+}
+
+/// Build SSE body from data-only events (OpenAI uses `data: {json}\n\n`).
+fn build_sse_body(events: &[serde_json::Value]) -> String {
+    let mut body = String::new();
+    for event in events {
+        body.push_str(&format!("data: {event}\n\n"));
+    }
+    body.push_str("data: [DONE]\n\n");
+    body
+}
